module bsg_dff
(
	input clk_i, 
	input [4-1:0] data_i,
	output [4-1:0] data_o
);

	reg [4-1:0] data_r;
	assign data_o = data_r;
	always @(posedge clk_i)
		data_r <= data_i;
endmodule

module bsg_dff_chain
(
	input clk_i,
	input [4-1:0] data_i,
	output [4-1:0] data_o
);

	reg [4-1:0] data_delayed;
	assign data_delayed = data_i;
	assign data_o = data_delayed[num_stages_p];

	bsg_dff
	ch_reg 
	(
		.clk_i(clk_i)
		,.data_i(data_delayed)
		,.data_o({data_delayed[3:1], data_delayed[3]})
	);
endmodule
